def _parse_market_q(q):
    ql = q.lower()
    city = lat = lon = None
    for name, coords in _CITY_COORDS.items():
        if name in ql:
            city = name.title()
            lat, lon = coords
            break
    temp_match = _re.search(r'(\d+\.?\d*)\s*[\xb0]?\s*(?:degrees?\s*)?(?:fahrenheit|f\b|celsius|c\b)', ql)
    if not temp_match:
        temp_match = _re.search(r'(\d+\.?\d*)\s*[\xb0]?\s*[fFcC]?\s*(?:or\s+)?(?:above|below|exceed|over|under|higher|lower)', ql)
        if not temp_match:
            temp_match = _re.search(r'(?:above|below|exceed|over|under|at least|reach)\s*(\d+\.?\d*)', ql)
    threshold = float(temp_match.group(1)) if temp_match else None
    is_f = 'fahrenheit' in ql or '\xb0f' in ql or (temp_match is not None and ql[temp_match.end()-1:temp_match.end()] == 'f')
    threshold_c = ((threshold - 32) * 5.0 / 9.0) if (is_f and threshold) else threshold
    is_above = any(w in ql for w in ['above', 'exceed', 'over', 'at least', 'reach', 'higher', 'warmer'])
    is_below = any(w in ql for w in ['below', 'under', 'lower', 'cooler', 'colder'])
    # Detect exact temperature questions: "be XÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ°C on" with no above/below
    is_exact = (not is_above and not is_below and threshold is not None
                and _re.search(r'be\s+\d+', ql) is not None)
    if is_exact:
        direction = "exact"
    elif is_above:
        direction = "above"
    else:
        direction = "below"
    metric = "temperature"
    if any(w in ql for w in ['rain', 'precipitation']): metric = 'precipitation'
    elif any(w in ql for w in ['snow']): metric = 'snow'
    elif any(w in ql for w in ['wind']): metric = 'wind'
    return {"city": city, "lat": lat, "lon": lon, "threshold": threshold,
            "threshold_c": threshold_c, "direction": direction, "metric": metric,
            "is_f": is_f, "is_exact": is_exact}

def _ncdf(x):
    return 0.5 * (1 + _math.erf(x / _math.sqrt(2)))


# ── Per-city sigma calibration from 60-day historical volatility ──────────
# Derived from Open-Meteo archive for each Polymarket resolution station.
# Values are in °C.  Higher std cities need wider sigma so bins stay
# spread across the distribution instead of collapsing onto one bin.
# Source: avg 7-day rolling std over last 60 days, converted F→C, scaled.
# Sigma calibration source: v3 reliability report (2139 resolved markets, 38 cities)
# Formula: sigma_tomorrow = max(rmse_f/1.8*1.2, std7_f/1.8*1.3, 1.5)
# sigma_today ~ 0.65 * sigma_tomorrow (reduced uncertainty same-day)
_CITY_SIGMA: dict = {
    # city_name_lower: (sigma_tomorrow_c, sigma_today_c)
    # ── US cities (RMSE-calibrated) ──
    "miami":          (3.4, 2.1),   # RMSE 2.0F, std7 4.0F → keep 3.4
    "los angeles":    (3.4, 2.1),   # low n, keep conservative
    "seattle":        (2.3, 1.5),   # RMSE 1.9F — tight, keep
    "chicago":        (2.8, 1.8),   # RMSE 3.4F → sig_floor 2.2, spring volatile
    "atlanta":        (2.5, 1.6),   # RMSE 3.2F → sig_floor 2.1
    "dallas":         (2.8, 1.8),   # RMSE 3.3F, outlier_rate 9.6% — wide
    "new york":       (2.6, 1.7),   # RMSE 3.6F (n=425) → sig_floor 2.4
    # ── Canada ──
    "toronto":        (6.0, 3.7),   # extreme seasonal swings — must stay wide
    # ── LATAM ──
    "buenos aires":   (2.6, 1.7),   # RMSE 3.8F → sig_floor 2.5 (was 2.4)
    "mexico city":    (2.3, 1.5),
    # ── Europe ──
    "london":         (1.8, 1.2),   # RMSE 2.1F (n=429) — tightest reliable data
    "munich":         (1.8, 1.2),   # RMSE 1.9F (n=24)
    "paris":          (1.8, 1.2),   # RMSE 2.1F (n=43)
    "milan":          (2.4, 1.6),   # RMSE 3.3F (n=12, watch)
    "warsaw":         (2.0, 1.3),   # RMSE 2.8F (n=12)
    # ── Middle East ──
    "ankara":         (2.3, 1.5),   # RMSE 2.5F (n=66), p95=5.0F — keep
    "tel aviv":       (1.8, 1.2),   # RMSE 1.9F (n=19) — tight
    # ── Asia ──
    "singapore":      (1.5, 1.0),   # RMSE 1.1F (n=16) — most stable globally
    "tokyo":          (1.8, 1.2),   # RMSE 1.6F (n=19)
    "seoul":          (2.2, 1.5),   # RMSE 2.9F (n=113) — sig_floor 1.95
    "shanghai":       (1.8, 1.2),   # RMSE 1.9F (n=16)
    "taipei":         (4.0, 2.6),   # RMSE 5.4F, outlier_rate 25% — very wide
    "hong kong":      (4.0, 2.6),   # RMSE 5.4F, outlier_rate 33% — very wide
    # ── Oceania ──
    "wellington":     (2.0, 1.3),   # RMSE 2.7F (n=66), p95=4.6F
    # ── Global fallback ──
    "__default__":    (2.5, 1.8),
}

# ── Per-city forecast bias correction (°C) ────────────────────────────────
# Source: station_reliability_report_v3.xlsx — 2139 matched resolved markets
# across 38 cities, Jan 2025 – Mar 2026. ERA5 vs Wunderground (Polymarket truth).
#
# Sign convention: positive _CITY_BIAS_C = OM overestimates WU → subtract.
#   ftemp -= _CITY_BIAS_C[city]   (positive = reduce, negative = increase)
#
# Correction threshold: |bias_f| >= 2.0°F AND n_used >= 10.
# Cities below threshold are monitored but not corrected yet.
#
# bias_f (°F) → bias_c (°C) = bias_f / 1.8, applied as negative (OM low → add)
#
# Corrected (|bias| >= 2.0F, n >= 10):
#   Buenos Aires:  ERA5 −3.0F vs WU (n=113) → add +1.64°C
#   New York:      ERA5 −2.1F vs WU (n=425) → add +1.19°C  ← strongest signal
#   Wellington:    ERA5 −2.1F vs WU (n=66)  → add +1.18°C
#   Los Angeles:   ERA5 +2.4F vs WU (n=7)   → subtract 1.17°C (small n, keep)
#   Taipei:        ERA5 +2.1F vs WU (n=12)  → subtract 1.15°C (25% outlier rate)
#
# Monitoring (0.8F <= |bias| < 2.0F, n >= 10): Munich, Paris, Hong Kong, Milan,
#   Chicago, Miami, Toronto, Sao Paulo, Shanghai, Tel Aviv, Seoul — correct when n>30
_CITY_BIAS_C: dict = {
    # Positive = OM overestimates (subtract from ftemp). Negative = OM underestimates (add).
    "los angeles":   +1.17,  # ERA5 +2.1F high vs KLAX (n=7, direction stable)
    "taipei":        +1.15,  # ERA5 +2.1F high (n=12, 25% outlier rate — apply carefully)
    "buenos aires":  -1.64,  # ERA5 −3.0F low vs WU (n=113, strong signal)
    "new york":      -1.19,  # ERA5 −2.1F low vs WU (n=425, highest confidence)
    "wellington":    -1.18,  # ERA5 −2.1F low vs WU (n=66)
}

def _city_sigma(city_name: str, is_tomorrow: bool) -> float:
    """Return calibrated sigma (°C) for a city based on historical volatility."""
    key = city_name.lower().strip()
    pair = _CITY_SIGMA.get(key, _CITY_SIGMA["__default__"])
    return pair[0] if is_tomorrow else pair[1]


def _build_signals(weather_markets, weather_cities):
    city_wx = {}
    if weather_cities:
        for c in weather_cities:
            city_wx[c["name"].lower()] = c
    # Diversify: round-robin across cities for better coverage
    by_city = {}
    for mkt in weather_markets:
        q = mkt.get("question", "")
        p = _parse_market_q(q)
        if not p["city"] or p["threshold_c"] is None:
            continue
        by_city.setdefault(p["city"].lower(), []).append((mkt, p))
    # Boundary-first sort: within each city put above/below bins before exact bins
    # so the round-robin reaches both boundary bins for every city before exact bins
    # consume the 60-signal cap.
    _recovery_cities_lower = {c.lower() for c in RECOVERY_CITIES} if RECOVERY_CITIES else set()
    for _c in by_city:
        by_city[_c].sort(key=lambda t: 0 if t[1]["direction"] in ("above", "below") else 1)
    # RECOVERY_CITIES first in iteration so both their boundary bins land in the pool
    # before the cap is reached; all other cities follow in alphabetical order.
    diverse = []
    idx = 0
    _recovery_first = sorted(_recovery_cities_lower & by_city.keys())
    _others = sorted(by_city.keys() - _recovery_cities_lower)
    cities = _recovery_first + _others
    # Pre-commit up to 3 exact bins per whitelist city before round-robin opens.
    # Select the 3 bins closest to the forecast center (temp_max from city_wx)
    # rather than the first 3 in threshold order (which are cold-tail bins).
    # Falls back to 20°C if no weather data — still better than threshold order.
    _EXACT_PER_CITY = 3
    for _wc in _recovery_first:
        _exact_bins = [t for t in by_city[_wc] if t[1]["direction"] == "exact"]
        if _exact_bins:
            _wx = city_wx.get(_wc)
            _fc = (_wx.get("temp_max") or _wx.get("temp", 20.0)) if _wx else 20.0
            _exact_bins.sort(key=lambda t: abs(t[1]["threshold_c"] - _fc))
            for _t in _exact_bins[:_EXACT_PER_CITY]:
                if len(diverse) < 60 and _t not in diverse:
                    diverse.append(_t)
    while len(diverse) < min(60, sum(len(v) for v in by_city.values())):
        added = False
        for c in cities:
            if idx < len(by_city[c]):
                diverse.append(by_city[c][idx])
                added = True
            if len(diverse) >= 60:
                break
        if not added:
            break
        idx += 1
    signals = []
    for mkt, p in diverse:
        wx = city_wx.get(p["city"].lower())
        # Determine if market is for today or tomorrow
        _q_lower = mkt.get("question", "").lower()
        _today = datetime.now(timezone.utc)
        _is_tomorrow = False
        _dm = _re.search(r'(?:march|april|may|june|july|aug|sep|oct|nov|dec|jan|feb)\s+(\d+)', _q_lower)
        if _dm:
            _qday = int(_dm.group(1))
            _is_tomorrow = _qday != _today.day
        # ── PRIMARY: Ensemble-based probability (82 members + 7 models) ──
        _used_ensemble = False
        _ens_fc = None
        _data_quality_override = None  # set below when recovery_exact redirects to static sigma
        _bias_c = _bias_agent.get_correction_c(p["city"]) if HAS_BIAS_AGENT else _CITY_BIAS_C.get(p["city"].lower(), 0.0)
        if _ENSEMBLE_AVAILABLE:
            try:
                _coords = _CITY_COORDS.get(p["city"].lower())
                if _coords:
                    _ens_prob, _ens_fc = _ensemble_prob(
                        city=p["city"],
                        lat=_coords[0], lon=_coords[1],
                        threshold_c=p["threshold_c"],
                        direction=p["direction"],
                        is_tomorrow=_is_tomorrow,
                        timezone="auto",
                        bias_correction_c=_bias_c,
                    )
                    our_prob = round(_ens_prob * 100, 1)
                    our_prob = max(0.1, min(99.9, our_prob))
                    # STRATEGY_REWRITE §3.2: hard cap lowered to 35%.
                    if p["direction"] == "exact":
                        our_prob = min(our_prob, 35.0)
                    # STRATEGY_REWRITE §3.3: also subtract _bias_c from the
                    # ensemble-path ftemp for display, so the operator dashboard
                    # reflects the bias-corrected mean (the prob already
                    # incorporates it via bias_correction_c above).
                    if _bias_c:
                        try:
                            ftemp_for_display = (_ens_fc.ensemble_mean if _ens_fc.n_ensemble_members > 0 else _ens_fc.multimodel_mean) - _bias_c
                        except Exception:
                            ftemp_for_display = None
                    # Extract ftemp for display (use ensemble mean)
                    ftemp = _ens_fc.ensemble_mean if _ens_fc.n_ensemble_members > 0 else _ens_fc.multimodel_mean
                    sigma = _ens_fc.blended_sigma
                    _used_ensemble = True
                    logger.debug(
                        "ENSEMBLE prob: city=%s thresh=%.1fC dir=%s prob=%.1f%% "
                        "members=%d models=%d sigma=%.2f quality=%s",
                        p["city"], p["threshold_c"], p["direction"], our_prob,
                        _ens_fc.n_ensemble_members, _ens_fc.n_models,
                        _ens_fc.blended_sigma, _ens_fc.data_quality,
                    )
            except Exception as _ens_err:
                logger.warning("Ensemble failed for %s, falling back to static sigma: %s", p["city"], _ens_err)

        # recovery_exact + quality=fallback: static sigma is more reliable than
        # the empty-member Gaussian (hardcoded 20°C center, 2.5°C sigma).
        # Redirect to the static-sigma block below and label data quality accordingly.
        if (_used_ensemble and _ens_fc is not None
                and _ens_fc.data_quality == "fallback"
                and RECOVERY_EXACT and p["direction"] == "exact"
                and p["city"].lower() in _recovery_cities_lower):
            _used_ensemble = False
            _data_quality_override = "static_sigma"
            logger.debug(
                "RECOVERY_EXACT_STATIC city=%s thr=%.1f — ensemble fallback, switching to static sigma",
                p["city"], p["threshold_c"],
            )

        # ── FALLBACK: Static sigma Gaussian CDF (old method) ──
        if not _used_ensemble:
            if wx:
                # Use forecasted daily HIGH, not current temp
                if _is_tomorrow and wx.get("temp_max_tomorrow") is not None:
                    ftemp = wx["temp_max_tomorrow"]
                    sigma = _city_sigma(p["city"], True)
                elif wx.get("temp_max") is not None:
                    ftemp = wx["temp_max"]
                    sigma = _city_sigma(p["city"], False)
                else:
                    ftemp = wx.get("temp", 20)
                    sigma = _city_sigma(p["city"], _is_tomorrow)
            else:
                ftemp = 20.0
                sigma = _city_sigma(p["city"], _is_tomorrow)
            # Anchor same-day forecast with real NWS observation if available
            if not _is_tomorrow and ACTIVE_TRADER_AVAILABLE:
                try:
                    import active_trader as _at
                    _obs_f = _at.get_obs_temp_f(p["city"])
                    if _obs_f is not None:
                        _obs_c = (_obs_f - 32) * 5.0 / 9.0
                        # STRATEGY_REWRITE §1.4 / §3.1: use real city timezone.
                        try:
                            from zoneinfo import ZoneInfo as _ZI
                            _tz_name = next((c.get("timezone","UTC") for c in CITIES if c["city"] == p["city"]), "UTC")
                            _now_hour = datetime.now(timezone.utc).astimezone(_ZI(_tz_name)).hour
                        except Exception:
                            _now_hour = datetime.now(timezone.utc).hour
                        _max_f = _at.max_achievable_today(_obs_f, _now_hour)
                        _max_c = (_max_f - 32) * 5.0 / 9.0
                        ftemp = _obs_c * 0.4 + min(_max_c, ftemp) * 0.6
                        sigma = max(_city_sigma(p["city"], False), sigma * 0.7)
                        logger.info("NWS obs anchor: city=%s obs=%.1fF max=%.1fF adj_ftemp=%.2fC", p["city"], _obs_f, _max_f, ftemp)
                except Exception as _obs_err:
                    logger.debug("NWS obs anchor failed for %s: %s", p["city"], _obs_err)
            # Apply per-city bias correction
            if _bias_c != 0.0:
                ftemp -= _bias_c
                logger.debug("Bias correction: city=%s adj=%.2fC -> ftemp=%.2fC", p["city"], _bias_c, ftemp)
            if p["direction"] == "exact":
                z_hi = (p["threshold_c"] + 0.5 - ftemp) / sigma
                z_lo = (p["threshold_c"] - 0.5 - ftemp) / sigma
                our_prob = round((_ncdf(z_hi) - _ncdf(z_lo)) * 100, 1)
            elif p["direction"] == "above":
                z = (ftemp - p["threshold_c"]) / sigma
                our_prob = round(_ncdf(z) * 100, 1)
            else:
                z = (p["threshold_c"] - ftemp) / sigma
                our_prob = round(_ncdf(z) * 100, 1)
            our_prob = max(0.1, min(99.9, our_prob))
            # STRATEGY_REWRITE §3.2: hard cap lowered to 35%.
            if p["direction"] == "exact":
                our_prob = min(our_prob, 35.0)
        # Use real market price from tokens
        _tkns = mkt.get('tokens', [])
        _yes_mp = 0
        for _tk in _tkns:
            if str(_tk.get('outcome', '')).lower() == 'yes':
                _yes_mp = float(_tk.get('price', 0) or 0)
                break
        mp = round(_yes_mp * 100, 1) if _yes_mp > 0 else max(5, min(95, our_prob))
        ev = round(our_prob - mp, 1)  # probability edge (percentage points)
        # Dollar EV: expected return per dollar risked = (p - P) / P
        # This properly weights cheap vs expensive contracts
        _p = our_prob / 100.0
        _P = max(0.01, mp / 100.0)
        ev_dollar = round((_p - _P) / _P * 100, 1)  # as percentage return on capital
        is_f = p.get("is_f", False)
        df = round(ftemp * 9 / 5 + 32, 1) if p.get("is_f") else round(ftemp, 1)
        unit = "F" if is_f else "C"
        kelly = round(max(0, (our_prob / 100 * (100 / max(0.1, mp)) - 1) / ((100 / max(0.1, mp)) - 1) * 100), 1) if mp > 0 else 0
        conf = min(5, max(1, int(abs(ev) / 10) + 1))
        agreement = "STRONG" if abs(ev) > 20 else "MODERATE" if abs(ev) > 10 else "WEAK"
        sig_type = "SKIP" if abs(ev) < 5 else ("BUY YES" if ev > 0 else "BUY NO")
        # ── Station edge overlay: refine with obs + physics ──
        # Capture pre-station-edge probability NOW, before any mutation.
        # This is the true ensemble/base value and must not be clobbered.
        _raw_prob_pre_se_pct: float = our_prob          # ensemble baseline
        _station_edge_prob_pct: float | None = None     # populated if SE runs
        _se_data = {}
        if _STATION_EDGE_AVAILABLE:
            try:
                _coords = _CITY_COORDS.get(p["city"].lower())
                if _coords:
                    _se = _station_prob(
                        city=p["city"], lat=_coords[0], lon=_coords[1],
                        threshold_c=p["threshold_c"], direction=p["direction"],
                        is_tomorrow=_is_tomorrow, bias_correction_c=_bias_c,
                    )
                    _station_edge_prob_pct = round(_se.probability * 100, 1)
                    _se_data = {
                        "station_source": _se.source,
                        "station_confidence": round(_se.confidence, 3),
                        "obs_temp_f": _se.obs_temp_f,
                        "obs_max_estimate_f": _se.obs_max_estimate_f,
                        "blend_weight_obs": round(_se.blend_weight_obs, 2),
                        "recommended_kelly": round(_se.recommended_size, 4),
                    }
                    if RECOVERY_MODE and RECOVERY_DISABLE_STATION_EDGE_OVERRIDE:
                        # Recovery mode: station-edge is logged for diagnostics only.
                        # our_prob is NOT mutated. All downstream EV/gate/sizing
                        # continue to use the unmodified ensemble probability.
                        logger.debug(
                            "RECOVERY_SE_BLOCKED city=%-12s se_prob=%.1f%% "
                            "ensemble_prob=%.1f%% — override suppressed",
                            p["city"], _station_edge_prob_pct, our_prob,
                        )
                    else:
                        # Non-recovery mode: station-edge overrides our_prob as before.
                        our_prob = round(_se.probability * 100, 1)
                        our_prob = max(0.1, min(99.9, our_prob))
                        ev = round(our_prob - mp, 1)
                        _p = our_prob / 100.0
                        ev_dollar = round((_p - _P) / _P * 100, 1)
                        kelly = round(_se.recommended_size * 100, 1)
                        conf = round(_se.confidence * 5, 0)  # scale 0-1 to 0-5
                        sig_type = "SKIP" if abs(ev) < 8 else ("BUY YES" if ev > 0 else "BUY NO")
            except Exception as _se_err:
                logger.debug("Station edge failed for %s: %s", p["city"], _se_err)
        # ── F-STRICT GATE + RECAL ─────────────────────────────────────
        # STRATEGY_REWRITE §2.1. Apply the recalibration map and the F-Strict
        # filter; if the signal does not pass, demote to SKIP and tag the
        # reason. Pilot-city restriction is enforced here too.
        #
        # Imports are separated from execution so import failures surface
        # with their actual exception text (not swallowed as "gate error").

        # ── Gate default state (always defined before any try block) ─────
        our_prob_recal = our_prob
        ev_recal = ev
        ev_dollar_recal = ev_dollar
        kelly_recal = kelly
        _gate_reason = "gate_not_run"
        _lane = "none"
        _recovery_log: dict = {}
        _ensemble_prob_pct = _raw_prob_pre_se_pct
        _date_parse_ok = False
        _mins_left = None
        _raw_prob = our_prob / 100.0
        _recal = our_prob  # fallback; overwritten on success

        # ── Step 1: imports (isolated so failures are visible) ───────────
        _gate_imports_ok = False
        try:
            from src.strategy_gate import (
                f_strict_pass, recal_prob, shadow_lane_ok,
                RECOVERY_EXACT_MIN_RECAL_PROB,
                RECOVERY_EXACT_MAX_PRICE,
            )
            from config import (
                ENABLE_F_STRICT, PILOT_CITY_ONLY, ABOVE_BELOW_SHADOW,
            )
            _gate_imports_ok = True
        except Exception as _imp_err:
            logger.warning(
                "GATE_IMPORT_ERROR city=%s exc=%s: %s",
                p.get("city"), type(_imp_err).__name__, _imp_err,
            )
            _gate_reason = f"gate_import_error: {type(_imp_err).__name__}: {_imp_err}"
            sig_type = "SKIP"

        # ── Step 2: gate execution ────────────────────────────────────────
        if _gate_imports_ok:
            try:
                _raw_prob = our_prob / 100.0
                _recal = round(recal_prob(_raw_prob) * 100.0, 1)

                # ── Date parsing: handles ISO 8601 AND display formats ──────
                _raw_end_str = mkt.get("end_date", "") or ""
                if _RECOVERY_GATE_OK:
                    _end_dt = parse_end_date_safe(_raw_end_str)
                else:
                    _end_dt = None
                    try:
                        _end_dt = datetime.fromisoformat(_raw_end_str.replace("Z", "+00:00"))
                    except Exception:
                        pass
                if _end_dt is not None:
                    _mins_left = (_end_dt - datetime.now(timezone.utc)).total_seconds() / 60.0
                    _date_parse_ok = True
                else:
                    logger.warning("end_date parse failed: %r — gate will block", _raw_end_str)

                # Ensemble baseline: pre-station-edge value for audit trail.
                _ensemble_prob_pct = _raw_prob_pre_se_pct  # true pre-SE ensemble baseline

                _gate_reason = ""
                _gate_ok = False
                _lane = "none"
                _recovery_log = {}

                # ── RECOVERY MODE: above/below gate (primary lane) ──────────
                if (RECOVERY_MODE and _RECOVERY_GATE_OK
                        and p["direction"] in ("above", "below")):
                    _bias_c_for_log = _bias_agent.get_correction_c(p["city"]) if HAS_BIAS_AGENT else 0.0
                    _ok, _why, _recovery_log = recovery_ab_pass(
                        city=p["city"],
                        direction=p["direction"],
                        market_price=mp / 100.0,
                        recal_prob=recal_prob(_raw_prob),
                        mins_to_resolution=_mins_left,
                        raw_prob=_raw_prob,
                        ensemble_prob=_ensemble_prob_pct / 100.0,
                        bias_correction_c=_bias_c_for_log,
                        sigma_c=float(p.get("sigma", 2.5) or 2.5),
                    )
                    _recovery_log["date_parse_ok"] = _date_parse_ok
                    _recovery_log["end_date_raw"] = _raw_end_str
                    if _ok:
                        _gate_ok = True
                        _lane = "recovery_above_below"
                    else:
                        _gate_reason = _why
                        if p["city"] in RECOVERY_CITIES:
                            logger.warning(
                                "RECOVERY_REJECT city=%s dir=%s mp=%.2f recal=%.3f mins=%s why=%s",
                                p["city"], p["direction"], mp,
                                recal_prob(_raw_prob), _mins_left, _why,
                            )
                elif not RECOVERY_MODE:
                    # ── Legacy gates (only active when RECOVERY_MODE=False) ──
                    if p["direction"] == "exact" and ENABLE_F_STRICT and _mins_left is not None:
                        _ok, _why, _rp = f_strict_pass(
                            price=mp / 100.0,
                            raw_prob=_raw_prob,
                            mins_to_resolution=_mins_left,
                            city=p["city"],
                            bin_type="exact",
                        )
                        if _ok:
                            _gate_ok = True
                            _lane = "f_strict"
                        _gate_reason = _why
                    elif p["direction"] in ("above", "below") and ABOVE_BELOW_SHADOW and _mins_left is not None:
                        _ok, _why = shadow_lane_ok(
                            raw_prob=_raw_prob,
                            price=mp / 100.0,
                            mins_to_resolution=_mins_left,
                        )
                        if _ok:
                            _gate_ok = True
                            _lane = "shadow_above_below"
                        _gate_reason = _why
                    if PILOT_CITY_ONLY and p["city"] != PILOT_CITY_ONLY:
                        _gate_ok = False
                        _gate_reason = f"pilot-city only ({PILOT_CITY_ONLY})"
                        _lane = "none"
                elif (RECOVERY_EXACT and p["direction"] == "exact"
                        and p["city"] in RECOVERY_CITIES and _mins_left is not None):
                    # ── RECOVERY MODE: exact-bin gate (secondary lane) ─────────
                    _ok, _why, _rp = f_strict_pass(
                        price=mp / 100.0,
                        raw_prob=_raw_prob,
                        mins_to_resolution=_mins_left,
                        city=p["city"],
                        bin_type="exact",
                        allow_unknown_rmse=True,        # recovery_exact: missing RMSE is "unknown but allowed"
                        recal_prob_min=RECOVERY_EXACT_MIN_RECAL_PROB,  # 0.20 vs F-Strict 0.22
                        price_max=RECOVERY_EXACT_MAX_PRICE,            # 0.25 vs F-Strict 0.20
                    )
                    if _ok:
                        _gate_ok = True
                        _lane = "recovery_exact"
                    else:
                        _gate_reason = _why
                        logger.warning(
                            "RECOVERY_REJECT city=%s dir=exact thr=%.1fC mp=%.2f recal=%.3f mins=%s why=%s",
                            p["city"], p["threshold_c"], mp, recal_prob(_raw_prob), _mins_left, _why,
                        )
                else:
                    # RECOVERY_MODE=True but direction/city not routed — always skip
                    _gate_reason = f"recovery_mode: direction '{p['direction']}' not routed"
                    _gate_ok = False

                if not _gate_ok:
                    sig_type = "SKIP"
                # Recompute EV/Kelly against the recalibrated prob (display + sizing)
                our_prob_recal = _recal
                ev_recal = round(our_prob_recal - mp, 1)
                _pr = our_prob_recal / 100.0
                _Pm = max(0.01, mp / 100.0)
                ev_dollar_recal = round((_pr - _Pm) / _Pm * 100.0, 1)
                kelly_recal = round(max(0.0, (_pr * (1.0 / _Pm) - 1.0) / ((1.0 / _Pm) - 1.0) * 100.0), 1) if mp > 0 else 0
            except Exception as _gate_err:
                logger.warning(
                    "GATE_EXEC_ERROR city=%s exc=%s: %s",
                    p.get("city"), type(_gate_err).__name__, _gate_err,
                    exc_info=False,
                )
                _gate_reason = f"gate_exec_error: {type(_gate_err).__name__}: {_gate_err}"
                sig_type = "SKIP"
                # our_prob_recal and other fields retain their default-state values

        # ── Recovery mode: fixed sizing override ─────────────────────────────
        if RECOVERY_MODE and DISABLE_KELLY and sig_type != "SKIP":
            kelly_recal = 0.0  # Kelly disabled
            # Fixed size will be applied at trade placement; store the cap here

        signals.append({
            "question": mkt.get("question", ""),
            "city": p["city"], "metric": p["metric"],
            "signal": sig_type, "confidence": conf,
            "our_prob": our_prob, "our_prob_recal": our_prob_recal,
            "lane": _lane, "gate_reason": _gate_reason,
            "market_price": round(mp, 1),
            "theo_ev": ev_recal, "theo_ev_raw": ev,
            "ev_dollar": ev_dollar_recal, "ev_dollar_raw": ev_dollar,
            "forecast": df, "unit": unit,
            "ftemp_c": round(ftemp, 3), "threshold_c": p["threshold_c"],
            "threshold": p["threshold"], "sigma": round(sigma, 2),
            "agreement": agreement,
            "models": list(_ens_fc.model_forecasts.keys()) if _ens_fc and _ens_fc.n_models > 0 else ["GFS", "ECMWF", "UKMO", "MF"],
            "prob_source": "ensemble" if _used_ensemble else "static_sigma",
            "ensemble_members": _ens_fc.n_ensemble_members if _ens_fc else 0,
            "ensemble_spread": round(_ens_fc.ensemble_max - _ens_fc.ensemble_min, 1) if _ens_fc and _ens_fc.n_ensemble_members > 0 else 0,
            "data_quality": _data_quality_override if _data_quality_override is not None else (_ens_fc.data_quality if _ens_fc else "fallback"),
            **_se_data,
            "kelly": kelly_recal, "kelly_raw": kelly,
            "active": mkt.get("active", True),
            "end_date": mkt.get("end_date", ""),
            "direction": p["direction"],
            "slug": mkt.get("slug", ""),
            "condition_id": mkt.get("condition_id", ""),
            "tokens": mkt.get("tokens", []),
            # ── Recovery audit trail ─────────────────────────────────────────
            # Probability chain (all values in percent, 0–100):
            #   raw_prob_pre_station_edge_pct  — ensemble output, no SE, no recal
            #   station_edge_prob_pct          — SE estimate (None if SE unavailable
            #                                    or suppressed but SE did not run)
            #   raw_prob_post_station_edge_pct — our_prob after SE step:
            #                                    == pre_se in recovery (SE blocked)
            #                                    == se_prob in non-recovery (SE ran)
            #   ensemble_prob_pct              — alias for raw_prob_pre_station_edge_pct
            #   recal_prob_pct                 — after recalibration map
            #   final_prob_used_pct            — what EV and gate actually used
            "_recovery_log": _recovery_log,
            "_raw_prob_pre_se_pct": _raw_prob_pre_se_pct,
            "_station_edge_prob_pct": _station_edge_prob_pct,
            "_raw_prob_post_se_pct": our_prob,     # == pre_se in recovery, se_prob otherwise
            "_ensemble_prob_pct": _ensemble_prob_pct,
            "_date_parse_ok": _date_parse_ok,
            "_mins_left": _mins_left,
        })
    # ── Post-process: normalize exact bin probabilities per city+date group ──
    # Each bin was computed independently with a Normal CDF slice.  When sigma
    # is tight (obs-anchored), one bin can absorb 99.9% of mass even though the
    # market's whole distribution must sum to 100%.  Group all "exact" bins for
    # the same city+end_date and re-weight so they form a proper distribution.
    _exact_groups: dict = {}
    for _si, _sig in enumerate(signals):
        if _sig.get('direction') == 'exact':
            if _sig.get('lane') == 'recovery_exact':
                continue  # partial pool — normalization would inflate; preserve raw CDF prob
            _gk = (_sig['city'], _sig.get('end_date', ''))
            _exact_groups.setdefault(_gk, []).append(_si)

    for _gk, _idxs in _exact_groups.items():
        if len(_idxs) < 2:
            continue  # single bin — nothing to normalize against
        _raw = [signals[i]['our_prob'] for i in _idxs]
        _tot = sum(_raw)
        if _tot <= 0:
            continue
        for _ii, _idx in enumerate(_idxs):
            _norm = round(_raw[_ii] / _tot * 100.0, 1)
            _norm = max(0.1, min(99.9, _norm))
            # Shrinkage: if model > 3× market, pull toward market price
            _mp = signals[_idx]['market_price']
            if _mp > 0 and _norm > 3.0 * _mp:
                _norm = round(min(_norm, 2.0 * _mp + 10.0), 1)
            _ev = round(_norm - _mp, 1)
            _p2 = _norm / 100.0
            _P2 = max(0.01, _mp / 100.0)
            _evd = round((_p2 - _P2) / _P2 * 100.0, 1)
            _kl = round(max(0, (_norm / 100 * (100 / max(0.1, _mp)) - 1) /
                           ((100 / max(0.1, _mp)) - 1) * 100), 1) if _mp > 0 else 0
            _st = "SKIP" if abs(_ev) < 5 else ("BUY YES" if _ev > 0 else "BUY NO")
            signals[_idx].update({
                'our_prob': _norm, 'theo_ev': _ev, 'ev_dollar': _evd,
                'kelly': _kl, 'signal': _st,
            })

    # Rank by dollar EV (cost-aware edge), not raw probability edge
    signals.sort(key=lambda s: abs(s.get("ev_dollar", 0)), reverse=True)

    # ── Milan 2-bin resolution check (runs every cycle) ──────────────────────
    # For each pending dq=good Milan pair whose market_end_date has passed,
    # fetch the ERA5 archive high, determine leg/pair outcomes, emit resolved log.
    def _check_2bin_resolution():
        import urllib.request as _ur
        import urllib.parse as _up
        import json as _js
        _today = datetime.now(timezone.utc).date()
        for _pid in list(_2BIN_PENDING.keys()):
            if _pid in _2BIN_RESOLVED:
                _2BIN_PENDING.pop(_pid, None)
                continue
            _snap = _2BIN_PENDING[_pid]
            try:
                _end_str = _snap["market_end_date"]
                _end_date = datetime.strptime(_end_str, "%Y-%m-%d").date()
            except Exception:
                continue
            if _end_date > _today:
                continue  # not yet resolvable
            # Shared setup
            _bin_A = _snap["bin_A_threshold_c"]
            _bin_B = _snap["bin_B_threshold_c"]
            _actual_high = None
            _resolution_source = None
            _leg_A = None
            _leg_B = None
            _winning_bin = None
            # ── 1. Polymarket resolution (primary, same-day) ──────────────────
            import re as _re2
            try:
                _edate = datetime.strptime(_end_str, "%Y-%m-%d")
                _pm_slug = (
                    f"highest-temperature-in-milan-on-"
                    f"{_edate.strftime('%B').lower()}-{_edate.day}-{_edate.year}"
                )
                _pm_url = f"https://gamma-api.polymarket.com/events?slug={_pm_slug}"
                _pm_req = _ur.Request(_pm_url, headers={"User-Agent": "weatheredge-bot/2.0"})
                with _ur.urlopen(_pm_req, timeout=10) as _pm_r:
                    _pm_data = _js.loads(_pm_r.read())
                _pm_mkts = (_pm_data[0].get("markets") or []) if _pm_data else []
                _leg_A_tag = f"be {int(_bin_A)}\u00b0C on"
                _leg_B_tag = f"be {int(_bin_B)}\u00b0C on"
                for _m in _pm_mkts:
                    if _m.get("umaResolutionStatus") != "resolved":
                        continue
                    _q = _m.get("question", "")
                    _prices = _js.loads(_m.get("outcomePrices", "[]"))
                    if not _prices:
                        continue
                    _is_yes = (_prices[0] == "1")
                    if _leg_A_tag in _q:
                        _leg_A = "WIN" if _is_yes else "LOSS"
                    if _leg_B_tag in _q:
                        _leg_B = "WIN" if _is_yes else "LOSS"
                    if _is_yes and _winning_bin is None:
                        _tm = _re2.search(r"be (\d+)", _q)
                        if _tm:
                            _winning_bin = int(_tm.group(1))
                            _actual_high = float(_winning_bin)
                if _leg_A is not None and _leg_B is not None:
                    _resolution_source = "polymarket"
            except Exception as _pe:
                logger.debug("2BIN_POLYMARKET_FETCH_ERR pair_id=%s: %s", _pid, _pe)
            # ── 2. ERA5 fallback (Polymarket unavailable or not yet resolved) ──
            if _resolution_source is None:
                try:
                    _params = _up.urlencode({
                        "latitude": 45.6306, "longitude": 8.7231,
                        "start_date": _end_str, "end_date": _end_str,
                        "daily": "temperature_2m_max",
                        "temperature_unit": "celsius", "timezone": "Europe/Rome",
                    })
                    _url = f"https://archive-api.open-meteo.com/v1/archive?{_params}"
                    _req = _ur.Request(_url, headers={"User-Agent": "weatheredge-bot/2.0"})
                    with _ur.urlopen(_req, timeout=20) as _r:
                        _arc = _js.loads(_r.read())
                    _vals = (_arc.get("daily") or {}).get("temperature_2m_max") or []
                    if not _vals or _vals[0] is None:
                        continue  # ERA5 not yet ingested — retry next cycle
                    _actual_high = float(_vals[0])
                    _resolution_source = "open-meteo-archive-era5"
                    _winning_bin = round(_actual_high)
                    _leg_A = "WIN" if _winning_bin == int(_bin_A) else "LOSS"
                    _leg_B = "WIN" if _winning_bin == int(_bin_B) else "LOSS"
                except Exception as _e:
                    logger.debug("2BIN_RESOLVE_FETCH_ERR pair_id=%s: %s", _pid, _e)
                    continue
            if _resolution_source is None:
                continue
            # Determine pair outcome from direct leg outcomes
            _pair_out = "WIN" if "WIN" in (_leg_A, _leg_B) else "LOSS"
            _winning_bin = _winning_bin if _winning_bin is not None else -1
            _actual_high = _actual_high if _actual_high is not None else float(_winning_bin)
            # Hypothetical PnL: $1 per leg, $2 total notional
            _pA = _snap["price_A_at_surfacing"]
            _pB = _snap["price_B_at_surfacing"]
            if _leg_A == "WIN":
                _pnl = (1.0 / _pA) - 2.0
            elif _leg_B == "WIN":
                _pnl = (1.0 / _pB) - 2.0
            else:
                _pnl = -2.0
            _pnl_pct = (_pnl / 2.0) * 100.0
            logger.info(
                "RECOVERY_2BIN_RESOLVED pair_id=%s city=Milan market_end_date=%s "
                "bin_A_threshold_c=%.1f bin_B_threshold_c=%.1f "
                "price_A_at_surfacing=%.4f price_B_at_surfacing=%.4f "
                "combined_market_cost_at_surfacing=%.4f "
                "raw_prob_A_at_surfacing=%.4f raw_prob_B_at_surfacing=%.4f "
                "combined_raw_prob_at_surfacing=%.4f "
                "raw_2bin_ev_pp_at_surfacing=%.2f "
                "forecast_center_c_at_surfacing=%.2f "
                "pair_midpoint_c_at_surfacing=%.1f "
                "sigma_c_at_surfacing=%.2f "
                "data_quality_at_surfacing=%s "
                "actual_high_c=%.1f resolution_source=%s "
                "leg_A_outcome=%s leg_B_outcome=%s pair_outcome=%s "
                "winning_bin_c=%d "
                "hypothetical_pair_pnl_usd=%.2f hypothetical_pair_pnl_pct=%.1f",
                _pid, _end_str,
                _bin_A, _bin_B,
                _pA, _pB,
                _snap["combined_market_cost_at_surfacing"],
                _snap["raw_prob_A_at_surfacing"], _snap["raw_prob_B_at_surfacing"],
                _snap["combined_raw_prob_at_surfacing"],
                _snap["raw_2bin_ev_pp_at_surfacing"],
                _snap["forecast_center_c_at_surfacing"],
                _snap["pair_midpoint_c_at_surfacing"],
                _snap["sigma_c_at_surfacing"],
                _snap["data_quality_at_surfacing"],
                _actual_high, _resolution_source,
                _leg_A, _leg_B, _pair_out,
                _winning_bin,
                _pnl, _pnl_pct,
            )
            _2BIN_RESOLVED.add(_pid)
            _2BIN_PENDING.pop(_pid, None)
            _save_2bin_pending()

    _check_2bin_resolution()

    # ── Adjacent 2-bin validation — Milan only, log-only, no execution ───────
    # Collects all Milan exact-bin signals (regardless of single-bin gate result),
    # forms adjacent pairs (threshold_c and threshold_c + 1.0°C), and logs each
    # pair's raw combined probability and market cost for analysis.
    # Raw combined prob = raw_prob_A + raw_prob_B — no recal map applied.
    # Records are NEVER added to the main signals list; no gate, no sizing, no execution.
    _2bin_candidates = []
    _milan_exact = sorted(
        [_s for _s in signals
         if _s.get("city", "").lower() == "milan"
         and _s.get("direction") == "exact"
         and _s.get("market_price", 0) > 0
         and _s.get("our_prob", 0) > 0],
        key=lambda _s: _s.get("threshold_c", 0.0),
    )
    for _bi in range(len(_milan_exact) - 1):
        _sA = _milan_exact[_bi]
        _sB = _milan_exact[_bi + 1]
        # Only bins that are exactly 1.0°C apart qualify as an adjacent pair
        if abs(_sB.get("threshold_c", 0.0) - _sA.get("threshold_c", 0.0) - 1.0) > 0.01:
            continue
        _raw_prob_A = min(round(_sA.get("_raw_prob_pre_se_pct", _sA["our_prob"]) / 100.0, 4), 0.35)
        _raw_prob_B = min(round(_sB.get("_raw_prob_pre_se_pct", _sB["our_prob"]) / 100.0, 4), 0.35)
        _price_A    = round(_sA["market_price"] / 100.0, 4)
        _price_B    = round(_sB["market_price"] / 100.0, 4)
        _combined_raw_prob = round(_raw_prob_A + _raw_prob_B, 4)
        _combined_cost     = round(_price_A + _price_B, 4)
        _raw_2bin_ev_pp    = round((_combined_raw_prob - _combined_cost) * 100.0, 2)
        _clears_5pp        = _raw_2bin_ev_pp >= 5.0
        _thr_A  = _sA.get("threshold_c", 0.0)
        _thr_B  = _sB.get("threshold_c", 0.0)
        _pair_mid = round((_thr_A + _thr_B) / 2.0, 1)
        _fc_c   = _sA.get("ftemp_c")
        _2bin_candidates.append({
            "city": "Milan",
            "forecast_center_c": round(_fc_c, 3) if _fc_c is not None else None,
            "pair_midpoint_c": _pair_mid,
            "bin_A_threshold_c": _thr_A,
            "bin_B_threshold_c": _thr_B,
            "bin_A_question": _sA.get("question", ""),
            "bin_B_question": _sB.get("question", ""),
            "price_A": _price_A,
            "price_B": _price_B,
            "combined_market_cost": _combined_cost,
            "raw_prob_A": _raw_prob_A,
            "raw_prob_B": _raw_prob_B,
            "combined_raw_prob": _combined_raw_prob,
            "sigma_c": _sA.get("sigma"),
            "data_quality": _sA.get("data_quality", "unknown"),
            "mins_to_resolution": round(_sA.get("_mins_left") or 0, 1),
            "raw_2bin_ev_pp": _raw_2bin_ev_pp,
            "clears_5pp_screen": _clears_5pp,
        })
        logger.info(
            "RECOVERY_2BIN_CANDIDATE city=Milan fc=%.2fC mid=%.1fC "
            "bins=[%.1f,%.1f] prices=[%.3f,%.3f] cost=%.3f "
            "raw_prob=[%.4f,%.4f] combined_raw=%.4f sigma=%.2f "
            "dq=%s mins=%.0f ev_pp=%.2f clears_5pp=%s",
            _fc_c if _fc_c is not None else float("nan"),
            _pair_mid,
            _thr_A, _thr_B,
            _price_A, _price_B,
            _combined_cost,
            _raw_prob_A, _raw_prob_B,
            _combined_raw_prob,
            _sA.get("sigma", float("nan")),
            _sA.get("data_quality", "unknown"),
            _sA.get("_mins_left") or 0,
            _raw_2bin_ev_pp,
            _clears_5pp,
        )

    # ── Best Milan pair summary — one line per cycle, isolated from signals ──
    # Selects the highest raw_2bin_ev_pp pair that clears +5pp.
    # Split by data quality: only dq=good pairs may be surfaced as candidates.
    # dq!=good (static_sigma, fallback, etc.) are logged for observation only.
    _qualifying_good   = [
        c for c in _2bin_candidates
        if c["clears_5pp_screen"]
        and c["data_quality"] == "good"
        and c["forecast_center_c"] is not None
        and c["sigma_c"] is not None
        and abs(c["pair_midpoint_c"] - c["forecast_center_c"]) <= 1.5 * c["sigma_c"]
    ]
    _qualifying_static = [c for c in _2bin_candidates if c["clears_5pp_screen"] and c["data_quality"] != "good"]

    # Helper: resolve end_date string from matching signal for pair_id construction.
    def _resolve_bp_end(bp):
        for _s in signals:
            if (_s.get("city", "").lower() == "milan"
                    and _s.get("direction") == "exact"
                    and _s.get("threshold_c") == bp["bin_A_threshold_c"]):
                _ed = _s.get("end_date", "") or ""
                return (_ed.isoformat() if hasattr(_ed, "isoformat") else str(_ed))[:10]
        return ""

    # Helper: format the standard best-pair log line.
    def _log_best(prefix, bp, pair_id):
        logger.info(
            "%s pair_id=%s city=Milan "
            "fc=%.2fC mid=%.1fC bins=[%.1f,%.1f] "
            "prices=[%.3f,%.3f] cost=%.3f "
            "raw_prob=[%.4f,%.4f] combined_raw=%.4f "
            "sigma=%.2f dq=%s mins=%.0f ev_pp=%.2f clears_5pp=True",
            prefix, pair_id,
            bp["forecast_center_c"] if bp["forecast_center_c"] is not None else float("nan"),
            bp["pair_midpoint_c"],
            bp["bin_A_threshold_c"], bp["bin_B_threshold_c"],
            bp["price_A"], bp["price_B"],
            bp["combined_market_cost"],
            bp["raw_prob_A"], bp["raw_prob_B"],
            bp["combined_raw_prob"],
            bp["sigma_c"] if bp["sigma_c"] is not None else float("nan"),
            bp["data_quality"],
            bp["mins_to_resolution"],
            bp["raw_2bin_ev_pp"],
        )

    # ── RECOVERY_2BIN_BEST_GOOD: actionable candidate (surfaced into signals) ──
    if _qualifying_good:
        _bp = max(_qualifying_good, key=lambda c: c["raw_2bin_ev_pp"])
        _bp_end = _resolve_bp_end(_bp)
        _pair_id = f"milan_2bin_{_bp['bin_A_threshold_c']:.0f}_{_bp['bin_B_threshold_c']:.0f}_{_bp_end}"
        _log_best("RECOVERY_2BIN_BEST_GOOD", _bp, _pair_id)
        # Append composite paper candidate to signals (isolated, no execution).
        # signal="PAPER_2BIN_YES" not in ("BUY YES","BUY NO") — tradeable excluded.
        # direction="exact_2bin" — EXACT_2BIN executor excluded.
        # lane="recovery_exact_2bin" — explicit executor skip guard.
        _bp_combined_prob_pct = round(_bp["combined_raw_prob"] * 100.0, 1)
        signals.append({
            "city": "Milan",
            "pair_id": _pair_id,
            "question": f"Milan 2bin [{_bp['bin_A_threshold_c']:.0f}\u00b0C\u2013{_bp['bin_B_threshold_c']:.0f}\u00b0C] {_bp_end}",
            "bin_A_threshold_c": _bp["bin_A_threshold_c"],
            "bin_B_threshold_c": _bp["bin_B_threshold_c"],
            "bin_A_question": _bp.get("bin_A_question", ""),
            "bin_B_question": _bp.get("bin_B_question", ""),
            "threshold_c": _bp["bin_A_threshold_c"],
            "direction": "exact_2bin",
            "lane": "recovery_exact_2bin",
            "signal": "PAPER_2BIN_YES",
            "paper_only": True,
            "paper_candidate_surfaced": True,
            "price_A": _bp["price_A"],
            "price_B": _bp["price_B"],
            "combined_market_cost": _bp["combined_market_cost"],
            "market_price": round(_bp["combined_market_cost"] * 100.0, 1),
            "raw_prob_A": _bp["raw_prob_A"],
            "raw_prob_B": _bp["raw_prob_B"],
            "combined_raw_prob": _bp["combined_raw_prob"],
            "our_prob": _bp_combined_prob_pct,
            "our_prob_recal": _bp_combined_prob_pct,  # no recal applied
            "forecast_center_c": _bp["forecast_center_c"],
            "ftemp_c": _bp["forecast_center_c"],
            "pair_midpoint_c": _bp["pair_midpoint_c"],
            "sigma_c": _bp["sigma_c"],
            "sigma": _bp["sigma_c"],
            "data_quality": _bp["data_quality"],
            "mins_to_resolution": _bp["mins_to_resolution"],
            "_mins_left": _bp["mins_to_resolution"],
            "raw_2bin_ev_pp": _bp["raw_2bin_ev_pp"],
            "theo_ev": _bp["raw_2bin_ev_pp"],
            "theo_ev_raw": _bp["raw_2bin_ev_pp"],
            "ev_dollar": 0.0,
            "kelly": 0,
            "kelly_raw": 0,
            "confidence": 0,
            "agreement": "PAPER",
            "gate_reason": "paper_2bin_candidate",
            "metric": "temp_max",
            "unit": "C",
            "end_date": _bp_end,
            "slug": "",
            "condition_id": "",
            "tokens": [],
            "prob_source": "raw_2bin",
            "ensemble_members": 0,
            "ensemble_spread": 0,
            "models": [],
        })
        logger.info(
            "RECOVERY_2BIN_SURFACED pair_id=%s paper_candidate_surfaced=True "
            "signal=PAPER_2BIN_YES lane=recovery_exact_2bin dq=good",
            _pair_id,
        )
        # Store in pending tracker — dq=good only, first surfacing only.
        if _pair_id not in _2BIN_PENDING and _pair_id not in _2BIN_RESOLVED and _bp["data_quality"] == "good":
            _2BIN_PENDING[_pair_id] = {
                "market_end_date": _bp_end,
                "bin_A_threshold_c": _bp["bin_A_threshold_c"],
                "bin_B_threshold_c": _bp["bin_B_threshold_c"],
                "price_A_at_surfacing": _bp["price_A"],
                "price_B_at_surfacing": _bp["price_B"],
                "combined_market_cost_at_surfacing": _bp["combined_market_cost"],
                "raw_prob_A_at_surfacing": _bp["raw_prob_A"],
                "raw_prob_B_at_surfacing": _bp["raw_prob_B"],
                "combined_raw_prob_at_surfacing": _bp["combined_raw_prob"],
                "raw_2bin_ev_pp_at_surfacing": _bp["raw_2bin_ev_pp"],
                "forecast_center_c_at_surfacing": _bp["forecast_center_c"] if _bp["forecast_center_c"] is not None else 0.0,
                "pair_midpoint_c_at_surfacing": _bp["pair_midpoint_c"],
                "sigma_c_at_surfacing": _bp["sigma_c"] if _bp["sigma_c"] is not None else 0.0,
                "data_quality_at_surfacing": _bp["data_quality"],
            }
            logger.info(
                "RECOVERY_2BIN_PENDING_ADDED pair_id=%s market_end_date=%s "
                "bins=[%.1f,%.1f] dq=%s ev_pp=%.2f",
                _pair_id, _bp_end,
                _bp["bin_A_threshold_c"], _bp["bin_B_threshold_c"],
                _bp["data_quality"], _bp["raw_2bin_ev_pp"],
            )
            _save_2bin_pending()

    # ── RECOVERY_2BIN_BEST_STATIC: observation only (never surfaced) ──────────
    if _qualifying_static:
        _bp_s = max(_qualifying_static, key=lambda c: c["raw_2bin_ev_pp"])
        _bp_s_end = _resolve_bp_end(_bp_s)
        _pair_id_s = f"milan_2bin_{_bp_s['bin_A_threshold_c']:.0f}_{_bp_s['bin_B_threshold_c']:.0f}_{_bp_s_end}"
        _log_best("RECOVERY_2BIN_BEST_STATIC", _bp_s, _pair_id_s)

    # ── RECOVERY_2BIN_BEST_NONE: no qualifying pair in either tier ────────────
    if not _qualifying_good and not _qualifying_static:
        _best_ev = max((c["raw_2bin_ev_pp"] for c in _2bin_candidates), default=0.0)
        logger.info(
            "RECOVERY_2BIN_BEST_NONE city=Milan n_pairs=%d best_ev_pp=%.2f",
            len(_2bin_candidates),
            _best_ev,
        )

    return signals


